// Pre-process & Hash Document
// Multi-anchor section detection with accent-normalized matching

const rawText = $input.first().json.text || $input.first().json.data || '';
const upstream = $input.first().json;

// ── Supplier / Country config — update per test case ──────────────────────
const SUPPLIER = 'Hertz';      // Change to: Hertz / Sixt / Goldcar
const COUNTRY  = 'ES';         // Change to: ES / DE
// ─────────────────────────────────────────────────────────────────────────

const hash = require('crypto')
  .createHash('md5')
  .update(rawText)
  .digest('hex');

const MAX_CHARS = 10000;
const WINDOW    = 1600;

function normalize(str) {
  return str.toLowerCase()
    .replace(/[áàâä]/g, 'a').replace(/[éèêë]/g, 'e')
    .replace(/[íìîï]/g, 'i').replace(/[óòôö]/g, 'o')
    .replace(/[úùûü]/g, 'u').replace(/ñ/g, 'n')
    .replace(/ß/g, 'ss').replace(/ç/g, 'c');
}

function preprocessText(text) {
  const lines = text.split('\n').map(l => l.trim()).filter(l => l.length > 0);
  const cleaned = lines.join('\n');
  if (cleaned.length <= MAX_CHARS) return cleaned;

  const cl = normalize(cleaned);

  const anchors = [
    ['insurance and excess waiver', 'opciones de seguro',
     'third party liability insurance', 'third party liability',
     'haftpflichtversicherung', 'seguro de responsabilidad', 'responsabilidad civil',
     'protection conditions', 'liability insurance', 'third party insurance'],
    ['karenzzeit', '60-minuten-karenz', 'reserva mantenida', 'reserva garantizada',
     'periodo de tolerancia', 'pickup grace', 'held for pickup', 'no-show policy',
     'will be held', 'reservation held', 'garantizara tu reserva',
     'seis (6) horas', 'booking guarantee', 'grace period'],
    ['driving licence', 'driving license', "driver's licence", "driver's license",
     'photocopies will not be accepted', 'international driving permit',
     'permiso de conducir', 'fuhrerschein', 'idp required',
     'age and driving', 'driving permit', 'permiso de conduccion'],
    ['reservation of credit', 'reserva de credito',
     'credit card', 'debit card', 'zahlungsmittel', 'tarjeta de credito',
     'payment method', 'method of payment', 'medios de pago', 'methods of payment'],
    ['cross-border', 'cross border', 'ausland', 'transfronter',
     'forbidden countr', 'zone i:', 'zona i:', 'zone ii', 'zona ii',
     'border crossing', 'authorized countries'],
  ];

  const chunks = [];
  const usedRanges = [];

  for (const anchorGroup of anchors) {
    let bestIdx = -1;
    for (const kw of anchorGroup) {
      const idx = cl.indexOf(normalize(kw));
      if (idx >= 0 && !usedRanges.some(([s, e]) => s <= idx && idx <= e)) {
        bestIdx = idx;
        break;
      }
    }
    if (bestIdx >= 0) {
      const start = Math.max(0, bestIdx - 100);
      const end   = Math.min(cleaned.length, bestIdx + WINDOW);
      chunks.push(cleaned.substring(start, end));
      usedRanges.push([start, end]);
    }
  }

  if (chunks.length > 0) {
    return chunks.join('\n\n[--- section ---]\n\n').substring(0, MAX_CHARS);
  }
  return cleaned.substring(0, MAX_CHARS);
}

const processedText = preprocessText(rawText);

return [{
  json: {
    processedText,
    documentHash: hash,
    supplier: SUPPLIER,
    pickupCountry: COUNTRY,
    sourceUrl: upstream.url || 'local',
    sourceType: upstream.sourceType || 'pdf',
    ingestedAt: new Date().toISOString(),
    characterCount: rawText.length,
    chunksFound: (processedText.match(/\[--- section ---\]/g) || []).length + 1
  }
}];

// Parse LLM JSON output and apply validation rules
const llmResponse = $input.first().json.message?.content || $input.first().json.text || '{}';
const upstream = $('Pre-process & Hash Document').first().json;

let extracted;
try {
  // Strip markdown fences if present (defensive)
  const cleaned = llmResponse.replace(/```json\n?|```\n?/g, '').trim();
  extracted = JSON.parse(cleaned);
} catch(e) {
  extracted = {
    tpl_amount: {value: null, confidence: 'LOW', source_text: null},
    grace_period_minutes: {value: null, confidence: 'LOW', source_text: null},
    licence_rules: {value: null, confidence: 'LOW', source_text: null},
    payment_rules: {value: null, confidence: 'LOW', source_text: null},
    cross_border_conditions: {value: null, confidence: 'LOW', source_text: null}
  };
}

// Validation rules
const CONFIDENCE_ORDER = ['HIGH', 'MEDIUM', 'LOW'];
const validationFlags = [];

// Grace period sanity check
if (extracted.grace_period_minutes?.value !== null) {
  const gp = parseInt(extracted.grace_period_minutes.value);
  if (isNaN(gp) || gp < 0 || gp > 480) {
    validationFlags.push('grace_period_out_of_range');
    extracted.grace_period_minutes.confidence = 'LOW';
  }
}

// Count low confidence fields
const lowConfidenceFields = Object.entries(extracted)
  .filter(([k, v]) => v?.confidence === 'LOW')
  .map(([k]) => k);

// Determine overall record status
const requiresHumanReview = lowConfidenceFields.length >= 2 || validationFlags.length > 0;
const overallConfidence = lowConfidenceFields.length === 0 ? 'HIGH' :
  lowConfidenceFields.length <= 2 ? 'MEDIUM' : 'LOW';

// Check if TPL is STATUTORY_MINIMUM — needs COB lookup
const tplNeedsCobLookup = extracted.tpl_amount?.value === 'STATUTORY_MINIMUM' ||
  extracted.tpl_amount?.value === null;

return [{
  json: {
    supplier: upstream.supplier,
    pickupCountry: upstream.pickupCountry,
    sourceUrl: upstream.sourceUrl,
    documentHash: upstream.documentHash,
    ingestedAt: upstream.ingestedAt,
    extractedAt: new Date().toISOString(),
    extractionModel: 'gpt-4o-mini',
    fields: extracted,
    overallConfidence,
    requiresHumanReview,
    lowConfidenceFields,
    validationFlags,
    tplNeedsCobLookup
  }
}];

// COB 2026 statutory minimum TPL lookup table
// Source: Council of Bureaux, Minimum Amount of Coverage 2026 (April 2026 edition)
// Disclaimer: Figures provided for information only. COB assumes no responsibility for accuracy.
const COB_2026 = {
  'DE': { personal_injury: '€7,500,000', property_damage: '€1,300,000', data_date: 'Dec-25', confidence: 'HIGH' },
  'ES': { personal_injury: '€70,000,000', property_damage: '€15,000,000', data_date: 'Dec-25', confidence: 'HIGH' },
  'IT': { personal_injury: '€6,450,000', property_damage: '€1,300,000', data_date: 'Dec-25', confidence: 'HIGH' },
  'GB': { personal_injury: '£1,200,000', property_damage: '£1,200,000', data_date: 'Dec-25', confidence: 'HIGH' },
  'NO': { personal_injury: 'Unlimited', property_damage: '€8,484,643', data_date: 'Dec-25', confidence: 'HIGH' },
  'CH': { personal_injury: 'CHF 5,000,000 per claim', property_damage: null, data_date: 'Nov-24', confidence: 'HIGH' },
  'AT': { personal_injury: null, property_damage: null, data_date: 'Oct-21', confidence: 'NONE', note: 'No data submitted to COB — manual verification required' },
  'FR': { personal_injury: 'Unlimited', property_damage: 'Unlimited', data_date: 'Mar-22', confidence: 'MEDIUM', note: 'Unlimited — not displayable as a numeric value' },
  'NL': { personal_injury: '€6,070,000', property_damage: '€1,220,000', data_date: 'Nov-20', confidence: 'MEDIUM', note: 'Stale — data from Nov-20' },
  'BE': { personal_injury: '€129,550,507', property_damage: 'Unlimited', data_date: 'Dec-25', confidence: 'HIGH' },
  'PL': { personal_injury: '€5,210,000', property_damage: '€1,050,000', data_date: 'Dec-25', confidence: 'HIGH' },
  'PT': { personal_injury: '€6,450,000', property_damage: '€1,300,000', data_date: 'Dec-25', confidence: 'HIGH' }
};

const country = $json.pickupCountry?.toUpperCase();
const cobData = COB_2026[country];

let tplResolved;
if (cobData && cobData.confidence !== 'NONE') {
  tplResolved = {
    value: `Personal injury: ${cobData.personal_injury} | Property damage: ${cobData.property_damage || 'see COB'}`,
    confidence: cobData.confidence,
    source: `COB Minimum Amount of Coverage 2026 (data date: ${cobData.data_date})`,
    source_url: 'https://www.cobx.org/sites/default/files/2026-04/MinimumAmountOfCoverage%202026.pdf',
    disclaimer: 'Figures provided for information only. COB assumes no responsibility for accuracy or future changes.',
    note: cobData.note || null
  };
} else {
  tplResolved = {
    value: null,
    confidence: 'NONE',
    source: 'COB 2026',
    source_url: 'https://www.cobx.org/sites/default/files/2026-04/MinimumAmountOfCoverage%202026.pdf',
    disclaimer: 'No COB data available for this country — manual verification required.',
    note: cobData?.note || 'Country not found in COB 2026 dataset'
  };
}

// Merge COB result into the fields
const updatedFields = { ...$json.fields };
updatedFields.tpl_amount = {
  ...updatedFields.tpl_amount,
  ...tplResolved,
  resolution_method: 'COB_LOOKUP'
};

return [{ json: { ...$json, fields: updatedFields, tplResolvedViaCob: true } }];

// Build the final API-ready output record
// This is what gets written to the T&C knowledge base
// and served via the aggregator API

const record = {
  // Identity
  record_id: `${$json.supplier}-${$json.pickupCountry}-${Date.now()}`,
  supplier: $json.supplier,
  pickup_country: $json.pickupCountry,

  // Provenance
  source_url: $json.sourceUrl,
  document_hash: $json.documentHash,
  ingested_at: $json.ingestedAt,
  extracted_at: $json.extractedAt,
  extraction_model: $json.extractionModel,

  // Status
  overall_confidence: $json.overallConfidence,
  status: 'APPROVED_AUTO', // auto-approved; human-reviewed records use 'APPROVED_HUMAN'

  // The five critical T&C fields
  fields: {
    tpl_amount: $json.fields.tpl_amount,
    grace_period_minutes: $json.fields.grace_period_minutes,
    licence_rules: $json.fields.licence_rules,
    payment_rules: $json.fields.payment_rules,
    cross_border_conditions: $json.fields.cross_border_conditions
  },

  // API metadata for downstream OTA consumption
  api_metadata: {
    extraction_method: 'AI',
    model_provider: 'OpenAI GPT-4o',
    data_disclaimer: 'T&C data is AI-extracted from supplier documents. Always verify critical information with the supplier directly.',
    last_updated: $json.extractedAt
  }
};

console.log('TermsIQ record ready for knowledge base:', JSON.stringify(record, null, 2));

return [{ json: record }];

// Detect source type from URL extension or explicit config
// In production: read from a supplier config table
const url = ($input.first().json.url || '').toLowerCase();

let sourceType = 'pdf'; // default
if (url.endsWith('.xlsx') || url.endsWith('.xls') || url.endsWith('.csv')) {
  sourceType = 'excel';
} else if (url.endsWith('.html') || url.endsWith('.htm') ||
           url.includes('/pages/') || url.includes('/mietbedingungen') ||
           url.includes('/terms') || url.includes('/informacion')) {
  sourceType = 'web';
}

// Allow explicit override via a field set in the trigger/config
const explicitType = $input.first().json.sourceType;
if (explicitType && ['pdf', 'web', 'excel'].includes(explicitType)) {
  sourceType = explicitType;
}

const binaryData = $input.first().binary;
const rawBytes   = binaryData ? Object.values(binaryData)[0] : null;

return [{
  json: {
    sourceType,
    url: $input.first().json.url || '',
    supplier: $input.first().json.supplier || 'Unknown',
    pickupCountry: $input.first().json.pickupCountry || 'XX',
    binaryKey: rawBytes ? Object.keys(binaryData)[0] : null,
  },
  binary: binaryData || {}
}];

// Extract clean text from HTML content
// Strips tags, scripts, nav, and excess whitespace
const raw = $input.first().json.data || $input.first().json.text || '';

// Remove script and style blocks
let text = raw
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
  .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, ' ')
  .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, ' ')
  .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, ' ');

// Replace block-level tags with newlines
text = text
  .replace(/<\/(p|div|h[1-6]|li|tr|td|th|br)>/gi, '\n')
  .replace(/<br\s*\/?>/gi, '\n');

// Strip remaining tags
text = text.replace(/<[^>]+>/g, ' ');

// Decode common HTML entities
text = text
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&nbsp;/g, ' ')
  .replace(/&euro;/g, '€')
  .replace(/&#8364;/g, '€')
  .replace(/&auml;/g, 'ä')
  .replace(/&ouml;/g, 'ö')
  .replace(/&uuml;/g, 'ü')
  .replace(/&szlig;/g, 'ß');

// Clean whitespace
text = text
  .split('\n')
  .map(l => l.trim())
  .filter(l => l.length > 0)
  .join('\n');

const upstream = $input.first().json;
return [{
  json: {
    text,
    characterCount: text.length,
    sourceType: upstream.sourceType,
    supplier: upstream.supplier,
    pickupCountry: upstream.pickupCountry,
    url: upstream.url,
  }
}];

// Extract text from Excel binary
// n8n stores binary data in the binary property
// We convert the binary to base64 and parse with a simple approach
// In production: use a dedicated Excel parsing library

const upstream = $input.first().json;

// For the POC: if the file is a CSV or plain-text Excel export,
// we can parse it directly. For binary .xlsx we output a placeholder
// that demonstrates the flow without requiring a full xlsx parser.

const binaryData = $input.first().binary;
let text = '';

if (binaryData) {
  // Try to decode as UTF-8 text (works for CSV and some Excel exports)
  try {
    const binaryKey = Object.keys(binaryData)[0];
    const base64 = binaryData[binaryKey].data;
    const decoded = Buffer.from(base64, 'base64').toString('utf-8');

    if (decoded.includes(',') || decoded.includes('\t')) {
      // Looks like CSV/TSV — parse rows
      const rows = decoded.split('\n')
        .map(r => r.trim())
        .filter(r => r.length > 0);
      text = '## Sheet: Rental Conditions\n' + rows.join('\n');
    } else if (decoded.includes('<')) {
      // Excel XML format — strip tags
      text = decoded.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
    } else {
      text = decoded;
    }
  } catch(e) {
    text = '[Excel binary detected — requires openpyxl or SheetJS parser in production]';
  }
} else if (upstream.text) {
  text = upstream.text;
}

return [{
  json: {
    text: text || '[No Excel content extracted]',
    characterCount: text.length,
    sourceType: upstream.sourceType,
    supplier: upstream.supplier,
    pickupCountry: upstream.pickupCountry,
    url: upstream.url,
  }
}];

// Save Output to File — n8n Cloud compatible
// fs is not available; return the record as output for inspection
// In self-hosted n8n with filesystem access, use fs.writeFileSync instead

const record = $input.first().json;

// Convert to JSON string for display/download
const jsonString = JSON.stringify(record, null, 2);

return [{
  json: {
    saved: true,
    record_id: record.record_id,
    supplier: record.supplier,
    pickup_country: record.pickup_country,
    status: record.status,
    overall_confidence: record.overall_confidence,
    fields_summary: {
      tpl_amount: record.fields?.tpl_amount?.value || null,
      grace_period_minutes: record.fields?.grace_period_minutes?.value || null,
      licence_rules: record.fields?.licence_rules?.value || null,
      payment_rules: record.fields?.payment_rules?.value || null,
      cross_border_conditions: record.fields?.cross_border_conditions?.value || null,
    },
    full_record: jsonString
  }
}];

// Build prompts for OpenAI
const data = $input.first().json;

const systemPrompt = `You are a car rental T&C extraction specialist. Extract exactly 5 fields from the document. Return ONLY valid JSON, no explanation.

Fields:
1. tpl_amount: TPL coverage amount OR "STATUTORY_MINIMUM" if document says meets legal requirements. null if absent.
2. grace_period_minutes: integer minutes reservation held after pickup time. null if absent.
3. licence_rules: what licences accepted/rejected/need IDP. null if no dedicated licence section.
4. payment_rules: which card types accepted/rejected. NOT deposit amounts.
5. cross_border_conditions: permitted/forbidden countries, penalties.

Confidence: HIGH=explicit, MEDIUM=implied, LOW=absent.
source_text: verbatim quote max 80 chars or null.

Hertz note: licence_rules and grace_period_minutes are absent from main PDF - return null+LOW. payment_rules and cross_border_conditions ARE present - extract them.
Goldcar note: grace period = garantizara tu reserva = 360 min.`;

const userPrompt = `Extract from this Supplier: ${data.supplier} | Country: ${data.pickupCountry}

DOCUMENT:
${data.processedText}

Return ONLY this JSON structure:
{"tpl_amount":{"value":null,"confidence":"LOW","source_text":null},"grace_period_minutes":{"value":null,"confidence":"LOW","source_text":null},"licence_rules":{"value":null,"confidence":"LOW","source_text":null},"payment_rules":{"value":null,"confidence":"LOW","source_text":null},"cross_border_conditions":{"value":null,"confidence":"LOW","source_text":null}}`;

return [{ json: { ...data, builtSystemPrompt: systemPrompt, builtUserPrompt: userPrompt } }];
